import group1 from '../assets/group1.jpg';
import group2 from '../assets/group2.jpg';
import group3 from '../assets/group3.jpg';
import group4 from '../assets/group4.jpg';
import group5 from '../assets/group5.jpg';
import group6 from '../assets/group6.jpg';

const mockGroups = [
    {
        id: 1,
        name: "Bretagne",
        image: group1,
        members: ["Alice", "Bob", "Charlie", "David", "Eva", "Frank"]
    },
    {
        id: 2,
        name: "Toscane",
        image: group2,
        members: ["Jean", "Marie", "Luc", "Claire", "Paul", "Julie"]
    },
    {
        id: 3,
        name: "Miami",
        image: group3,
        members: ["Max", "Léa", "Sophie", "Tom", "Emma", "Nina"]
    },
    {
        id: 4,
        name: "New-York",
        image: group4,
        members: ["Zack", "Nora", "Sam", "Ali", "Ivy", "Noah"]
    },
    {
        id: 5,
        name: "Saint-Tropez",
        image: group5,
        members: ["Yasmine", "Hugo", "Clara", "Leo", "Lina", "Alex"]
    },
    {
        id: 6,
        name: "Crète",
        image: group6,
        members: ["Milo", "Sarah", "Theo", "Ines", "Louis", "Chloe"]
    },
];

export const fetchGroups = () => {
    return new Promise((resolve) => {
        setTimeout(() => {
            resolve(mockGroups);
        }, 500);
    });
};
